import React, { useState, useMemo, useCallback, useEffect } from 'react';
import { 
  Diamond, Search, Calendar, Users, MapPin, Star, 
  LogOut, Home, BookOpen, Heart, User, Filter,
  ChevronRight, Check, ChevronDown, X, Bed, Loader2,
  Moon, Clock, CreditCard, Trash2, AlertCircle
} from 'lucide-react';
import { getHotels } from './services/hotelService';
import { getHotelRooms } from './services/roomService';
import { createBooking, getMyBookings, cancelBooking } from './services/bookingService';

// MODAL STYLE DATE PICKER
const CustomDatePicker = ({ label, value, onChange, min, icon: Icon }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [currentMonth, setCurrentMonth] = useState(new Date());

  const getDaysInMonth = (year, month) => {
    const firstDay = new Date(year, month, 1);
    const lastDay = new Date(year, month + 1, 0);
    const daysInMonth = lastDay.getDate();
    const startingDay = firstDay.getDay();
    const days = [];
    for (let i = 0; i < startingDay; i++) days.push(null);
    for (let i = 1; i <= daysInMonth; i++) days.push(i);
    return days;
  };

  const formatDate = (dateStr) => {
    if (!dateStr) return '';
    return new Date(dateStr).toLocaleDateString('en-GB', {
      day: '2-digit',
      month: 'short',
      year: 'numeric',
    });
  };

  const isDateDisabled = (day) => {
    if (!day) return false;
    const date = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), day);
    const minDate = min ? new Date(min) : new Date();
    minDate.setHours(0, 0, 0, 0);
    return date < minDate;
  };

  const isSelected = (day) => {
    if (!day || !value) return false;
    const selected = new Date(value);
    return selected.getDate() === day && 
           selected.getMonth() === currentMonth.getMonth() && 
           selected.getFullYear() === currentMonth.getFullYear();
  };

  const selectDate = (day) => {
    if (!day || isDateDisabled(day)) return;
    const date = new Date(currentMonth.getFullYear(), currentMonth.getMonth(), day);
    onChange(date.toISOString().split('T')[0]);
    setIsOpen(false);
  };

  const days = getDaysInMonth(currentMonth.getFullYear(), currentMonth.getMonth());
  const monthNames = ["January","February","March","April","May","June",
    "July","August","September","October","November","December"];

  return (
    <div className="relative">
      <label className="block text-xs text-gray-500 uppercase mb-1 ml-1">{label}</label>
      <button
        type="button"
        onClick={() => setIsOpen(true)}
        className="w-full flex items-center gap-2 pl-4 pr-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl text-white hover:bg-slate-800/50 transition-colors"
      >
        <Icon className="w-5 h-5 text-cyan-400" />
        {value ? formatDate(value) : "Select date"}
      </button>

      {isOpen && (
        <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/70 backdrop-blur-sm">
          <div className="bg-slate-900 w-[340px] rounded-2xl border border-white/10 p-4 shadow-2xl">
            <div className="flex justify-between items-center mb-4">
              <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1))} className="p-2 rounded-lg hover:bg-white/10 text-white">
                <ChevronRight className="w-5 h-5 rotate-180" />
              </button>
              <h2 className="text-white font-semibold">{monthNames[currentMonth.getMonth()]} {currentMonth.getFullYear()}</h2>
              <button onClick={() => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1))} className="p-2 rounded-lg hover:bg-white/10 text-white">
                <ChevronRight className="w-5 h-5" />
              </button>
            </div>
            <div className="grid grid-cols-7 text-center text-gray-400 text-xs mb-2">
              {["Su","Mo","Tu","We","Th","Fr","Sa"].map((d) => <div key={d}>{d}</div>)}
            </div>
            <div className="grid grid-cols-7 gap-1">
              {days.map((day, idx) => day ? (
                <button
                  key={idx}
                  disabled={isDateDisabled(day)}
                  onClick={() => selectDate(day)}
                  className={`h-9 rounded-lg text-sm transition-all ${
                    isSelected(day) ? 'bg-cyan-500 text-white' : isDateDisabled(day) ? 'text-gray-600 cursor-not-allowed' : 'text-white hover:bg-cyan-500/30'
                  }`}
                >
                  {day}
                </button>
              ) : <div key={idx} />)}
            </div>
            <button onClick={() => setIsOpen(false)} className="w-full mt-4 py-2 bg-white/10 rounded-lg text-white hover:bg-white/20">Close</button>
          </div>
        </div>
      )}
    </div>
  );
};

// ALERT MODAL COMPONENT
const AlertModal = ({ isOpen, onClose, title, message, type = 'error' }) => {
  if (!isOpen) return null;
  
  const bgColor = type === 'error' ? 'bg-red-500/10 border-red-500/30' : 'bg-green-500/10 border-green-500/30';
  const iconColor = type === 'error' ? 'text-red-400' : 'text-green-400';
  const buttonColor = type === 'error' ? 'bg-red-500 hover:bg-red-600' : 'bg-green-500 hover:bg-green-600';
  
  return (
    <div className="fixed inset-0 z-[10000] flex items-center justify-center bg-black/80 backdrop-blur-sm">
      <div className={`bg-slate-900 rounded-2xl p-6 max-w-md w-full border ${bgColor} shadow-2xl`}>
        <div className="flex items-center gap-3 mb-4">
          <div className={`w-12 h-12 rounded-full flex items-center justify-center ${bgColor}`}>
            <AlertCircle className={`w-6 h-6 ${iconColor}`} />
          </div>
          <h3 className="text-xl font-bold text-white">{title}</h3>
        </div>
        <p className="text-gray-300 mb-6 leading-relaxed">{message}</p>
        <button 
          onClick={onClose}
          className={`w-full py-3 ${buttonColor} text-white rounded-xl font-medium transition-colors`}
        >
          OK, I Understand
        </button>
      </div>
    </div>
  );
};

const Dashboard = ({ user, onLogout }) => {
  const [activeTab, setActiveTab] = useState('browse');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedGuests, setSelectedGuests] = useState(2);
  const [checkIn, setCheckIn] = useState('');
  const [checkOut, setCheckOut] = useState('');
  const [showGuestDropdown, setShowGuestDropdown] = useState(false);
  const [selectedHotel, setSelectedHotel] = useState(null);
  const [selectedRoom, setSelectedRoom] = useState(null);
  const [bookingSuccess, setBookingSuccess] = useState(false);
  const [hoveredHotel, setHoveredHotel] = useState(null);
  
  // Alert modal state
  const [alertModal, setAlertModal] = useState({
    isOpen: false,
    title: '',
    message: '',
    type: 'error'
  });
  
  const [hotels, setHotels] = useState([]);
  const [rooms, setRooms] = useState([]);
  const [myBookings, setMyBookings] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const guestOptions = [1, 2, 3, 4, 5, 6, 7, 8];
  const canBook = checkIn && checkOut;

  const numberOfNights = useMemo(() => {
    if (!checkIn || !checkOut) return 0;
    const start = new Date(checkIn);
    const end = new Date(checkOut);
    const diffTime = Math.abs(end - start);
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    return diffDays;
  }, [checkIn, checkOut]);

  useEffect(() => {
    fetchHotels();
    if (activeTab === 'bookings') {
      fetchMyBookings();
    }
  }, [activeTab]);

  const fetchHotels = async () => {
    try {
      setLoading(true);
      const response = await getHotels();
      if (response.success) {
        const transformedHotels = response.data.map(hotel => ({
          id: hotel._id,
          name: hotel.name,
          location: `${hotel.location.city}, ${hotel.location.country}`,
          price: hotel.starRating * 500,
          rating: hotel.starRating,
          image: hotel.images[0] || 'https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800&q=80',
          amenities: hotel.amenities,
          description: hotel.description,
          maxGuests: 4,
          roomTypes: ['Standard', 'Deluxe', 'Suite']
        }));
        setHotels(transformedHotels);
      }
    } catch (err) {
      setError('Failed to load hotels');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const fetchMyBookings = async () => {
    try {
      setLoading(true);
      const response = await getMyBookings();
      if (response.success) {
        setMyBookings(response.data);
      }
    } catch (err) {
      console.error('Failed to load bookings', err);
    } finally {
      setLoading(false);
    }
  };

  const fetchHotelRooms = async (hotelId) => {
    try {
      setLoading(true);
      const response = await getHotelRooms(hotelId);
      if (response.success) {
        setRooms(response.data);
      }
    } catch (err) {
      setError('Failed to load rooms');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleCancelBooking = async (bookingId) => {
    if (!window.confirm('Are you sure you want to cancel this booking?')) return;
    
    try {
      setLoading(true);
      const response = await cancelBooking(bookingId);
      if (response.success) {
        await fetchMyBookings();
      }
    } catch (err) {
      alert('Failed to cancel booking: ' + (err.response?.data?.error || err.message));
    } finally {
      setLoading(false);
    }
  };

  const filteredHotels = useMemo(() => {
    let filtered = hotels;
    if (searchQuery.trim()) {
      filtered = filtered.filter(hotel => 
        hotel.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        hotel.location.toLowerCase().includes(searchQuery.toLowerCase())
      );
    }
    filtered = filtered.filter(hotel => hotel.maxGuests >= selectedGuests);
    return filtered;
  }, [searchQuery, selectedGuests, hotels]);

  const handleSearchChange = useCallback((e) => {
    setSearchQuery(e.target.value);
  }, []);

  const handleCheckInChange = useCallback((value) => {
    setCheckIn(value);
    if (checkOut && new Date(checkOut) <= new Date(value)) {
      setCheckOut('');
    }
  }, [checkOut]);

  const handleCheckOutChange = useCallback((value) => {
    setCheckOut(value);
  }, []);

  const handleGuestSelect = useCallback((num) => {
    setSelectedGuests(num);
    setShowGuestDropdown(false);
  }, []);

  const toggleGuestDropdown = useCallback(() => {
    setShowGuestDropdown(prev => !prev);
  }, []);

  const handleBookNow = useCallback(async (hotel) => {
    if (!checkIn || !checkOut) {
      alert('Please select check-in and check-out dates first');
      return;
    }
    setSelectedHotel(hotel);
    await fetchHotelRooms(hotel.id);
  }, [checkIn, checkOut]);

  const handleConfirmBooking = async () => {
    if (!selectedRoom) {
      alert('Please select a room');
      return;
    }
    
    try {
      const bookingData = {
        hotel: selectedHotel.id,
        room: selectedRoom._id,
        checkIn,
        checkOut,
        guests: selectedGuests,
        totalPrice: selectedRoom.pricePerNight * numberOfNights
      };
      
      const response = await createBooking(bookingData);
      if (response.success) {
        setBookingSuccess(true);
        setTimeout(() => {
          setBookingSuccess(false);
          setSelectedHotel(null);
          setSelectedRoom(null);
          setActiveTab('bookings');
        }, 2000);
      }
    } catch (err) {
      // Check if it's a date conflict error (409 status)
      if (err.response?.status === 409) {
        const errorMsg = err.response?.data?.error || 'This room is already booked for these dates.';
        setAlertModal({
          isOpen: true,
          title: 'Room Already Occupied',
          message: errorMsg,
          type: 'error'
        });
      } else {
        alert('Booking failed: ' + (err.response?.data?.error || err.message));
      }
    }
  };

  const closeAlertModal = () => {
    setAlertModal(prev => ({ ...prev, isOpen: false }));
  };

  const formatDate = (dateString) => {
    if (!dateString) return '';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-GB', { day: '2-digit', month: '2-digit', year: 'numeric' });
  };

  const formatDateLong = (dateString) => {
    if (!dateString) return '';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });
  };

  const Sidebar = () => (
    <div className="w-64 bg-slate-900/50 border-r border-white/10 p-6 flex flex-col h-full">
      <div className="flex items-center gap-2 mb-8 cursor-pointer" onClick={() => setActiveTab('browse')}>
        <Diamond className="w-8 h-8 text-cyan-400" />
        <span className="text-xl font-bold bg-gradient-to-r from-cyan-400 to-purple-400 bg-clip-text text-transparent">AI'STAY</span>
      </div>
      <nav className="space-y-2 flex-1">
        <SidebarItem icon={Home} label="Browse Hotels" active={activeTab === 'browse'} onClick={() => setActiveTab('browse')} />
        <SidebarItem icon={BookOpen} label="My Bookings" active={activeTab === 'bookings'} onClick={() => setActiveTab('bookings')} />
        <SidebarItem icon={Heart} label="Favorites" active={activeTab === 'favorites'} onClick={() => setActiveTab('favorites')} />
        <SidebarItem icon={User} label="Profile" active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} />
      </nav>
      <div className="pt-6 border-t border-white/10">
        <div className="flex items-center gap-3 mb-4">
          <div className="w-10 h-10 rounded-full bg-gradient-to-r from-cyan-500 to-purple-500 flex items-center justify-center font-bold">
            {user?.name?.charAt(0) || 'U'}
          </div>
          <div>
            <p className="font-medium text-sm">{user?.name || 'User'}</p>
            <p className="text-xs text-gray-400">{user?.email || 'user@example.com'}</p>
          </div>
        </div>
        <button onClick={onLogout} className="flex items-center gap-2 text-red-400 hover:text-red-300 transition-colors text-sm">
          <LogOut className="w-4 h-4" /> Sign Out
        </button>
      </div>
    </div>
  );

  const SidebarItem = ({ icon: Icon, label, active, onClick }) => (
    <button onClick={onClick} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl transition-all duration-300 ${
      active ? 'bg-gradient-to-r from-cyan-500/20 to-purple-500/20 border border-cyan-500/30 text-cyan-400' : 'text-gray-400 hover:bg-white/5 hover:text-white'
    }`}>
      <Icon className="w-5 h-5" />
      <span className="font-medium">{label}</span>
    </button>
  );

  const MyBookings = () => (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold">My Bookings</h2>
        <span className="text-gray-400 text-sm">{myBookings.length} booking{myBookings.length !== 1 ? 's' : ''}</span>
      </div>
      
      {myBookings.length === 0 ? (
        <div className="bg-white/5 backdrop-blur-xl rounded-2xl p-8 text-center border border-white/10">
          <BookOpen className="w-16 h-16 text-gray-600 mx-auto mb-4" />
          <p className="text-gray-400">No bookings yet. Start exploring hotels!</p>
          <button onClick={() => setActiveTab('browse')} className="mt-4 px-6 py-2 bg-gradient-to-r from-cyan-500 to-purple-500 rounded-lg font-medium hover:shadow-lg transition-all duration-300">
            Browse Hotels
          </button>
        </div>
      ) : (
        <div className="grid gap-4">
          {myBookings.map((booking) => {
            const nights = Math.ceil((new Date(booking.checkOutDate) - new Date(booking.checkInDate)) / (1000 * 60 * 60 * 24));
            const pricePerNight = Math.round(booking.totalPrice / nights);
            
            return (
              <div key={booking._id} className="bg-white/5 backdrop-blur-xl rounded-2xl overflow-hidden border border-white/10 hover:border-cyan-500/30 transition-all">
                <div className="flex flex-col md:flex-row">
                  <div className="md:w-48 h-48 md:h-auto relative">
                    <img 
                      src={booking.hotel?.images?.[0] || 'https://images.unsplash.com/photo-1566073771259-6a8506099945?w=800&q=80'} 
                      alt={booking.hotel?.name}
                      className="w-full h-full object-cover"
                    />
                    <div className="absolute top-2 left-2 bg-black/60 backdrop-blur-sm px-2 py-1 rounded-lg">
                      <span className={`text-xs font-medium ${
                        booking.status === 'confirmed' ? 'text-green-400' : 
                        booking.status === 'cancelled' ? 'text-red-400' : 'text-yellow-400'
                      }`}>
                        {booking.status}
                      </span>
                    </div>
                  </div>
                  
                  <div className="flex-1 p-6">
                    <div className="flex justify-between items-start mb-4">
                      <div>
                        <h3 className="font-bold text-xl mb-1">{booking.hotel?.name || 'Hotel'}</h3>
                        <p className="text-gray-400 text-sm flex items-center gap-1">
                          <MapPin className="w-4 h-4" />
                          {booking.hotel?.location?.city || 'Location'}, {booking.hotel?.location?.country || ''}
                        </p>
                      </div>
                      <div className="text-right">
                        <span className="text-2xl font-bold text-cyan-400">${booking.totalPrice}</span>
                        <p className="text-gray-500 text-xs">total</p>
                      </div>
                    </div>

                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
                      <div className="bg-white/5 rounded-xl p-3">
                        <p className="text-xs text-gray-500 mb-1 flex items-center gap-1">
                          <Bed className="w-3 h-3" /> Room
                        </p>
                        <p className="font-medium text-sm capitalize">{booking.room?.type || 'Standard'}</p>
                        <p className="text-xs text-gray-400">#{booking.room?.roomNumber || 'N/A'}</p>
                      </div>
                      
                      <div className="bg-white/5 rounded-xl p-3">
                        <p className="text-xs text-gray-500 mb-1 flex items-center gap-1">
                          <Calendar className="w-3 h-3" /> Check-in
                        </p>
                        <p className="font-medium text-sm">{formatDate(booking.checkInDate)}</p>
                      </div>
                      
                      <div className="bg-white/5 rounded-xl p-3">
                        <p className="text-xs text-gray-500 mb-1 flex items-center gap-1">
                          <Calendar className="w-3 h-3" /> Check-out
                        </p>
                        <p className="font-medium text-sm">{formatDate(booking.checkOutDate)}</p>
                      </div>
                      
                      <div className="bg-white/5 rounded-xl p-3">
                        <p className="text-xs text-gray-500 mb-1 flex items-center gap-1">
                          <Moon className="w-3 h-3" /> Nights
                        </p>
                        <p className="font-medium text-sm">{nights} night{nights !== 1 ? 's' : ''}</p>
                        <p className="text-xs text-gray-400">${pricePerNight}/night</p>
                      </div>
                    </div>

                    <div className="flex flex-wrap items-center gap-4 text-sm mb-4">
                      <span className="flex items-center gap-1 text-gray-400">
                        <Users className="w-4 h-4" /> {booking.guests} guest{booking.guests !== 1 ? 's' : ''}
                      </span>
                      <span className="text-gray-600">•</span>
                      <span className="text-gray-400">
                        Booked on {new Date(booking.createdAt).toLocaleDateString()}
                      </span>
                    </div>

                    {booking.status !== 'cancelled' && (
                      <div className="flex justify-end">
                        <button 
                          onClick={() => handleCancelBooking(booking._id)}
                          disabled={loading}
                          className="flex items-center gap-2 px-4 py-2 bg-red-500/10 hover:bg-red-500/20 text-red-400 rounded-lg transition-colors text-sm font-medium"
                        >
                          <Trash2 className="w-4 h-4" />
                          Cancel Booking
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );

  const BookingModal = () => {
    if (!selectedHotel) return null;
    
    const calculatedTotal = selectedRoom ? selectedRoom.pricePerNight * numberOfNights : 0;
    
    const canSelectRoom = (room) => room.capacity >= selectedGuests;
    
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
        <div className="bg-slate-900 rounded-3xl p-8 max-w-2xl w-full border border-white/10 shadow-2xl max-h-[90vh] overflow-y-auto">
          {bookingSuccess ? (
            <div className="text-center py-8">
              <div className="w-20 h-20 bg-green-500/20 rounded-full flex items-center justify-center mx-auto mb-4">
                <Check className="w-10 h-10 text-green-400" />
              </div>
              <h3 className="text-2xl font-bold mb-2">Booking Confirmed!</h3>
              <p className="text-gray-400">Your reservation is confirmed.</p>
            </div>
          ) : (
            <>
              <div className="flex justify-between items-start mb-6">
                <h3 className="text-2xl font-bold">Select Room & Confirm</h3>
                <button onClick={() => {setSelectedHotel(null); setSelectedRoom(null);}} className="p-2 hover:bg-white/10 rounded-lg transition-colors">
                  <X className="w-5 h-5" />
                </button>
              </div>
              
              <div className="flex items-center gap-4 p-4 bg-white/5 rounded-xl mb-6">
                <img src={selectedHotel.image} alt={selectedHotel.name} className="w-24 h-24 rounded-lg object-cover" />
                <div className="flex-1">
                  <h4 className="font-bold text-lg">{selectedHotel.name}</h4>
                  <p className="text-gray-400 text-sm flex items-center gap-1">
                    <MapPin className="w-4 h-4" /> {selectedHotel.location}
                  </p>
                  <div className="flex items-center gap-2 mt-2">
                    <Star className="w-4 h-4 text-yellow-400 fill-yellow-400" />
                    <span className="font-bold">{selectedHotel.rating}</span>
                  </div>
                </div>
              </div>

              {numberOfNights > 0 && (
                <div className="mb-4 p-3 bg-cyan-500/10 border border-cyan-500/20 rounded-xl">
                  <div className="flex items-center justify-between text-sm">
                    <span className="flex items-center gap-2 text-cyan-400">
                      <Clock className="w-4 h-4" />
                      {numberOfNights} night{numberOfNights !== 1 ? 's' : ''} selected
                    </span>
                    <span className="text-gray-400">
                      {formatDateLong(checkIn)} → {formatDateLong(checkOut)}
                    </span>
                  </div>
                </div>
              )}

              <div className="mb-6">
                <h4 className="font-bold mb-4 flex items-center gap-2">
                  <Bed className="w-5 h-5 text-cyan-400" />
                  Available Rooms
                  <span className="text-xs font-normal text-gray-400 ml-2">
                    (for {selectedGuests} guests)
                  </span>
                </h4>
                {loading ? (
                  <div className="flex justify-center p-8">
                    <Loader2 className="w-8 h-8 text-cyan-400 animate-spin" />
                  </div>
                ) : rooms.length === 0 ? (
                  <p className="text-gray-400 text-center py-4">No rooms available</p>
                ) : (
                  <div className="space-y-3">
                    {rooms.map((room) => {
                      const isSelectable = canSelectRoom(room);
                      const isSelected = selectedRoom?._id === room._id;
                      
                      return (
                        <div 
                          key={room._id}
                          onClick={() => isSelectable && setSelectedRoom(room)}
                          className={`p-4 rounded-xl border transition-all ${
                            isSelected 
                              ? 'border-cyan-500 bg-cyan-500/10' 
                              : isSelectable
                                ? 'border-white/10 hover:border-white/30 cursor-pointer'
                                : 'border-red-500/30 bg-red-500/5 cursor-not-allowed opacity-60'
                          }`}
                        >
                          <div className="flex justify-between items-start">
                            <div>
                              <h5 className={`font-bold capitalize ${!isSelectable ? 'text-gray-500' : ''}`}>
                                {room.type} Room #{room.roomNumber}
                                {!isSelectable && (
                                  <span className="ml-2 text-xs text-red-400 font-normal">
                                    (Cannot accommodate {selectedGuests} guests)
                                  </span>
                                )}
                              </h5>
                              <p className={`text-sm ${isSelectable ? 'text-gray-400' : 'text-gray-600'}`}>
                                {room.description}
                              </p>
                              <div className="flex flex-wrap gap-2 mt-2">
                                {room.amenities?.map((amenity, idx) => (
                                  <span key={idx} className={`px-2 py-1 rounded text-xs ${
                                    isSelectable ? 'bg-white/5 text-gray-300' : 'bg-white/5 text-gray-600'
                                  }`}>
                                    {amenity}
                                  </span>
                                ))}
                              </div>
                            </div>
                            <div className="text-right">
                              <span className={`text-xl font-bold ${isSelectable ? 'text-cyan-400' : 'text-gray-600'}`}>
                                ${room.pricePerNight}
                              </span>
                              <p className="text-gray-500 text-xs">/night</p>
                              <p className={`text-sm mt-1 ${
                                room.capacity >= selectedGuests ? 'text-green-400' : 'text-red-400'
                              }`}>
                                Max {room.capacity} guest{room.capacity !== 1 ? 's' : ''}
                              </p>
                            </div>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>

              <div className="space-y-3 text-sm mb-6 p-4 bg-white/5 rounded-xl">
                <div className="flex justify-between py-2 border-b border-white/10">
                  <span className="text-gray-400">Check-in</span>
                  <span className="font-medium">{checkIn ? formatDateLong(checkIn) : 'Not selected'}</span>
                </div>
                <div className="flex justify-between py-2 border-b border-white/10">
                  <span className="text-gray-400">Check-out</span>
                  <span className="font-medium">{checkOut ? formatDateLong(checkOut) : 'Not selected'}</span>
                </div>
                <div className="flex justify-between py-2 border-b border-white/10">
                  <span className="text-gray-400">Duration</span>
                  <span className="font-medium">{numberOfNights > 0 ? `${numberOfNights} night${numberOfNights !== 1 ? 's' : ''}` : '-'}</span>
                </div>
                <div className="flex justify-between py-2 border-b border-white/10">
                  <span className="text-gray-400">Guests</span>
                  <span className="font-medium">{selectedGuests}</span>
                </div>
                {selectedRoom && (
                  <>
                    <div className="flex justify-between py-2 border-b border-white/10">
                      <span className="text-gray-400">Room</span>
                      <span className="font-medium capitalize">{selectedRoom.type} #{selectedRoom.roomNumber}</span>
                    </div>
                    <div className="flex justify-between py-2 border-b border-white/10">
                      <span className="text-gray-400">Price per night</span>
                      <span className="font-medium">${selectedRoom.pricePerNight}</span>
                    </div>
                    <div className="flex justify-between items-center pt-3">
                      <span className="text-gray-400 flex items-center gap-2">
                        <CreditCard className="w-4 h-4" /> Total
                      </span>
                      <div className="text-right">
                        <span className="text-3xl font-bold text-cyan-400">${calculatedTotal}</span>
                        <p className="text-xs text-gray-500 mt-1">
                          {selectedRoom.pricePerNight} × {numberOfNights} nights
                        </p>
                      </div>
                    </div>
                  </>
                )}
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => {setSelectedHotel(null); setSelectedRoom(null);}}
                  className="flex-1 py-3 bg-white/10 rounded-xl font-medium hover:bg-white/20 transition-colors"
                >
                  Cancel
                </button>
                <button 
                  onClick={handleConfirmBooking}
                  disabled={!selectedRoom || loading || numberOfNights === 0}
                  className="flex-1 py-3 bg-gradient-to-r from-cyan-500 to-purple-500 rounded-xl font-medium hover:shadow-lg transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  {loading ? 'Processing...' : `Pay $${calculatedTotal}`}
                </button>
              </div>
            </>
          )}
        </div>
      </div>
    );
  };

  return (
    <div className="min-h-screen bg-slate-950 text-white flex">
      <Sidebar />
      <main className="flex-1 p-8 overflow-y-auto relative">
        {activeTab === 'browse' && (
          <BrowseHotels 
            searchQuery={searchQuery}
            onSearchChange={handleSearchChange}
            checkIn={checkIn}
            onCheckInChange={handleCheckInChange}
            checkOut={checkOut}
            onCheckOutChange={handleCheckOutChange}
            selectedGuests={selectedGuests}
            onGuestSelect={handleGuestSelect}
            showGuestDropdown={showGuestDropdown}
            onToggleGuestDropdown={toggleGuestDropdown}
            filteredHotels={filteredHotels}
            onBookNow={handleBookNow}
            guestOptions={guestOptions}
            hoveredHotel={hoveredHotel}
            setHoveredHotel={setHoveredHotel}
            canBook={canBook}
            loading={loading}
            numberOfNights={numberOfNights}
          />
        )}
        {activeTab === 'bookings' && <MyBookings />}
        {activeTab === 'favorites' && (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold">Favorites</h2>
            <div className="bg-white/5 backdrop-blur-xl rounded-2xl p-8 text-center border border-white/10">
              <Heart className="w-16 h-16 text-gray-600 mx-auto mb-4" />
              <p className="text-gray-400">No favorites yet. Start browsing!</p>
            </div>
          </div>
        )}
        {activeTab === 'profile' && (
          <div className="space-y-6">
            <h2 className="text-2xl font-bold">Profile</h2>
            <div className="bg-white/5 backdrop-blur-xl rounded-2xl p-6 max-w-md border border-white/10">
              <div className="flex items-center gap-4 mb-6">
                <div className="w-20 h-20 rounded-full bg-gradient-to-r from-cyan-500 to-purple-500 flex items-center justify-center text-2xl font-bold">
                  {user?.name?.charAt(0) || 'U'}
                </div>
                <div>
                  <h3 className="text-xl font-bold">{user?.name || 'User'}</h3>
                  <p className="text-gray-400">{user?.email || 'user@example.com'}</p>
                </div>
              </div>
              <div className="space-y-4">
                <div className="p-4 bg-white/5 rounded-xl">
                  <p className="text-sm text-gray-400 mb-1">Member Since</p>
                  <p className="font-medium">{new Date(user?.createdAt).toLocaleDateString() || 'April 2026'}</p>
                </div>
                <div className="p-4 bg-white/5 rounded-xl">
                  <p className="text-sm text-gray-400 mb-1">Total Bookings</p>
                  <p className="font-medium">{myBookings.length}</p>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>
      {selectedHotel && <BookingModal />}
      
      {/* ALERT MODAL */}
      <AlertModal 
        isOpen={alertModal.isOpen}
        onClose={closeAlertModal}
        title={alertModal.title}
        message={alertModal.message}
        type={alertModal.type}
      />
    </div>
  );
};

const BrowseHotels = React.memo(({ 
  searchQuery, 
  onSearchChange, 
  checkIn, 
  onCheckInChange, 
  checkOut, 
  onCheckOutChange, 
  selectedGuests, 
  onGuestSelect,
  showGuestDropdown,
  onToggleGuestDropdown,
  filteredHotels, 
  onBookNow,
  guestOptions,
  hoveredHotel,
  setHoveredHotel,
  canBook,
  loading,
  numberOfNights
}) => {
  const today = new Date().toISOString().split('T')[0];

  return (
    <div className="space-y-6">
      <div className="bg-white/5 backdrop-blur-xl rounded-2xl p-4 border border-white/10">
        <div className="grid md:grid-cols-5 gap-4">
          <div className="md:col-span-2 relative">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400 pointer-events-none" />
            <input
              type="text"
              placeholder="Search hotels or destinations..."
              value={searchQuery}
              onChange={onSearchChange}
              className="w-full pl-12 pr-4 py-3 bg-slate-900/50 border border-white/10 rounded-xl focus:border-cyan-500/50 focus:outline-none text-white"
              autoComplete="off"
              spellCheck="false"
            />
          </div>

          <CustomDatePicker 
            label="Check In"
            value={checkIn}
            onChange={onCheckInChange}
            min={today}
            icon={Calendar}
          />

          <CustomDatePicker 
            label="Check Out"
            value={checkOut}
            onChange={onCheckOutChange}
            min={checkIn || today}
            icon={Calendar}
          />

          <div className="relative">
            <label className="block text-xs text-gray-500 uppercase tracking-wider mb-1 ml-1">Guests</label>
            <div className="relative">
              <Users className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-cyan-400 pointer-events-none" />
              <button
                type="button"
                onClick={onToggleGuestDropdown}
                className="w-full pl-12 pr-10 py-3 bg-slate-900/50 border border-white/10 rounded-xl focus:border-cyan-500/50 focus:outline-none text-white text-left flex items-center justify-between hover:bg-slate-800/50 transition-colors"
              >
                <span>{selectedGuests} Guests</span>
                <ChevronDown className={`w-4 h-4 text-gray-400 transition-transform ${showGuestDropdown ? 'rotate-180' : ''}`} />
              </button>
              
              {showGuestDropdown && (
                <div className="absolute top-full left-0 right-0 mt-2 bg-slate-900 border border-white/10 rounded-xl overflow-hidden shadow-xl max-h-60 overflow-y-auto z-50">
                  {guestOptions.map(num => (
                    <button
                      key={num}
                      type="button"
                      onClick={() => onGuestSelect(num)}
                      className={`w-full px-4 py-3 text-left hover:bg-white/10 transition-colors flex items-center justify-between ${
                        selectedGuests === num ? 'bg-cyan-500/20 text-cyan-400' : 'text-white'
                      }`}
                    >
                      <span>{num} Guests</span>
                      {selectedGuests === num && <Check className="w-4 h-4" />}
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {!canBook && (
        <div className="bg-yellow-500/10 border border-yellow-500/30 rounded-xl p-3 flex items-center gap-2 text-yellow-400 text-sm">
          <Calendar className="w-4 h-4" />
          <span>Please select check-in and check-out dates to book a hotel</span>
        </div>
      )}

      {numberOfNights > 0 && (
        <div className="bg-cyan-500/10 border border-cyan-500/30 rounded-xl p-3 flex items-center justify-between text-cyan-400 text-sm">
          <div className="flex items-center gap-2">
            <Moon className="w-4 h-4" />
            <span>{numberOfNights} night{numberOfNights !== 1 ? 's' : ''} selected</span>
          </div>
          <span className="text-gray-400">Prices will be calculated accordingly</span>
        </div>
      )}

      <div className="flex justify-between items-center">
        <div className="text-gray-400">
          Showing <span className="text-white font-bold">{filteredHotels.length}</span> properties
          <span className="text-cyan-400 text-sm ml-2">(for {selectedGuests} guests)</span>
        </div>
        <button className="flex items-center gap-2 px-4 py-2 bg-white/5 backdrop-blur-xl border border-white/10 rounded-lg hover:bg-white/10 transition-colors">
          <Filter className="w-4 h-4" /> Filters
        </button>
      </div>

      {loading ? (
        <div className="flex justify-center p-12">
          <Loader2 className="w-12 h-12 text-cyan-400 animate-spin" />
        </div>
      ) : (
        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredHotels.map(hotel => (
            <HotelCard 
              key={hotel.id} 
              hotel={hotel} 
              onBookNow={onBookNow}
              isHovered={hoveredHotel === hotel.id}
              onHover={() => setHoveredHotel(hotel.id)}
              onLeave={() => setHoveredHotel(null)}
              canBook={canBook}
            />
          ))}
        </div>
      )}
    </div>
  );
});

const HotelCard = React.memo(({ hotel, onBookNow, isHovered, onHover, onLeave, canBook }) => {
  return (
    <div 
      className="group bg-slate-900/50 rounded-2xl overflow-hidden border border-white/10 hover:border-cyan-500/50 transition-all duration-500 hover:shadow-xl hover:shadow-cyan-500/10 relative"
      onMouseEnter={onHover}
      onMouseLeave={onLeave}
    >
      <div className="relative h-48 overflow-hidden">
        <img src={hotel.image} alt={hotel.name} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110" />
        <div className="absolute top-4 right-4 bg-white/10 backdrop-blur-md px-2 py-1 rounded-lg flex items-center gap-1">
          <Star className="w-4 h-4 text-yellow-400 fill-yellow-400" />
          <span className="font-bold text-sm">{hotel.rating}</span>
        </div>
        
        {isHovered && (
          <div className="absolute inset-0 bg-black/70 backdrop-blur-sm flex items-center justify-center transition-all duration-300">
            <div className="text-center p-4">
              <Users className="w-8 h-8 text-cyan-400 mx-auto mb-2" />
              <p className="text-lg font-bold mb-1">{hotel.maxGuests} Persons</p>
              <p className="text-sm text-gray-300">Maximum capacity per room</p>
              <div className="mt-3 flex flex-wrap justify-center gap-1">
                {hotel.roomTypes.slice(0, 2).map((type, idx) => (
                  <span key={idx} className="px-2 py-1 bg-white/20 rounded text-xs">
                    {type}
                  </span>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
      
      <div className="p-5">
        <div className="flex justify-between items-start mb-2">
          <div>
            <h3 className="font-bold text-lg group-hover:text-cyan-400 transition-colors">{hotel.name}</h3>
            <div className="flex items-center gap-1 text-gray-400 text-sm">
              <MapPin className="w-4 h-4" /> {hotel.location}
            </div>
          </div>
          <div className="flex items-center gap-1 text-xs text-gray-400 bg-white/5 px-2 py-1 rounded-lg">
            <Users className="w-3 h-3" />
            <span>Max {hotel.maxGuests}</span>
          </div>
        </div>
        <p className="text-gray-400 text-sm mb-4 line-clamp-2">{hotel.description}</p>
        <div className="flex flex-wrap gap-2 mb-4">
          {hotel.amenities.map((amenity, idx) => (
            <span key={idx} className="px-2 py-1 bg-white/5 rounded-md text-xs text-gray-300 border border-white/10">
              {amenity}
            </span>
          ))}
        </div>
        <div className="flex justify-between items-center pt-4 border-t border-white/10">
          <div>
            <span className="text-2xl font-bold text-cyan-400">${hotel.price}</span>
            <span className="text-gray-500 text-sm">/night</span>
          </div>
          
          <button 
            onClick={() => onBookNow(hotel)}
            disabled={!canBook}
            className={`
              px-4 py-2 rounded-lg font-medium transition-all duration-300
              ${canBook 
                ? 'bg-gradient-to-r from-cyan-500 to-purple-500 hover:shadow-lg hover:shadow-cyan-500/25 text-white' 
                : 'bg-gray-700 text-gray-500 cursor-not-allowed'
              }
            `}
          >
            {canBook ? 'Book Now' : 'Select Dates'}
          </button>
        </div>
      </div>
    </div>
  );
});

export default Dashboard;
